def summarize_sales(sales):
    categories = []
    for record in sales:
        if record['category'] not in categories:
            categories.append(record['category'])

    totals = {}
    for cat in categories:
        total_amount = 0
        for record in sales:
            if record['category'] == cat:
                total_amount += record['amount']
        totals[cat] = total_amount
    return totals

